  { json: { search: 'Junior AI Engineer', location: 'Lahore, Pakistan' } },
  { json: { search: 'Junior AI Engineer', location: 'Karachi, Pakistan' } }
];

function isPakistaniJob(job) {
  const location = (job.location || '').toLowerCase();
  const pakistaniCities = ['islamabad', 'lahore', 'karachi', 'rawalpindi', 'peshawar', 'multan', 'faisalabad', 'quetta', 'gilgit', 'pakistan'];
  return pakistaniCities.some(city => location.includes(city));
}

const results = [];
const seen = new Set();

for (const input of $input.all()) {
  const jobs = input.json?.data || [];
  for (const job of jobs) {
    if (!job.job_id || seen.has(job.job_id)) continue;
    if (!isPakistaniJob(job)) continue;
    seen.add(job.job_id);
    results.push({ json: job });
  }
}

return results;

const AI_KEYWORDS = [
  'ai engineer',
  'junior ai',
  'ai/ml',
  'ai ml',
  'agentic',
  'artificial intelligence',
  'machine learning',
  'ml engineer',
  'automation engineer',
  'ai specialist'
];

const keywords = AI_KEYWORDS.map(k => k.toLowerCase());

return $input.all().filter(item => {
  const title = (item.json.title || '').toLowerCase();
  const tags = (item.json.tags || '').toLowerCase();
  const searchText = title + ' ' + tags;
  return keywords.some(kw => searchText.includes(kw));
});

// Matches patterns like: '2 years', '3+ years', '2-4 years', '2 years of experience'
// Captures the minimum number of years required.
const EXP_RE = /(\d+)\s*(?:[-–]\s*\d+)?\s*\+?\s*years?(?:\s+of)?(?:\s+experience)?/gi;

function minYearsRequired(text) {
  const matches = [...text.matchAll(EXP_RE)];
  if (matches.length === 0) return null;
  return Math.min(...matches.map(m => parseInt(m[1], 10)));
}

return $input.all().filter(item => {
  const text = [
    (item.json.title       || ''),
    (item.json.description || '')
  ].join(' ');

  const minYears = minYearsRequired(text);

  // No experience mentioned — let it through (junior/mid-level friendly)
  if (minYears === null) return true;

  // Mentioned — only keep if less than 5 years (junior/mid-level)
  // Reject if 5+ years (senior level)
  return minYears < 5;
});

// Get existing job IDs from the sheet (first input)
const allInputs = $input.all();
if (allInputs.length === 0) return [];

const sheetData = Array.isArray(allInputs[0].json) ? allInputs[0].json : [];
const existingIds = new Set();

sheetData.forEach(row => {
  if (row.job_id) existingIds.add(String(row.job_id));
});

// Filter out duplicates from remaining inputs
const results = [];
for (let i = 1; i < allInputs.length; i++) {
  const job = allInputs[i].json;
  if (job.job_id && !existingIds.has(String(job.job_id))) {
    results.push({ json: job });
  }
}

return results;
